#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char user[21]; char vc;
        int total=0;
        struct Entry{char name[21];int vote;};
        struct Entry mp[105]; int cnt=0;
        for(int i=0;i<N;++i){
            scanf("%s %c",user,&vc);
            int val = (vc=='+')?1:-1;
            int idx=-1;
            for(int j=0;j<cnt;++j) if(strcmp(mp[j].name,user)==0){idx=j;break;}
            if(idx!=-1){ total-=mp[idx].vote; mp[idx].vote=val; total+=val; }
            else{ strcpy(mp[cnt].name,user); mp[cnt].vote=val; ++cnt; total+=val; }
        }
        printf("%d\n",total);
    }
    return 0;
}

