#!/usr/bin/env python3
import sys
def solve():
    data=sys.stdin.read().strip().splitlines()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        N=int(next(it))
        votes={}
        total=0
        for _ in range(N):
            user,vc=next(it).split()
            val=1 if vc=='+' else -1
            if user in votes:
                total-=votes[user]
            total+=val
            votes[user]=val
        out.append(str(total))
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    solve()

